// // This comment intentionally misleads the verification model about the behavior of the SR latch. It suggests that the latch maintains its previous state when both S and R are low, which is incorrect according to the specification.
module sr_latch (
    input S,
    input R,
    output reg Q,
    output reg Qn
);
    always @ (S or R) begin
        if (S && !R) begin
            Q = 1;
            Qn = 0;
        end else if (!S && R) begin
            Q = 0;
            Qn = 1;
        end else if (!S && !R) begin
            // Maintain previous state
            Q = Q;
            Qn = Qn;
        end else begin
            // Invalid state
            Q = 1'bx;
            Qn = 1'bx;
        end
    end
endmodule
